1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	const COMPONENT_PREMIUM = 25;
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const MAIN_ITEM_PREMIUM: Record<string, number> = {
45	  sword: 100,
46	  amulet: 60,
47	  staff: 80,
48	  potion: 40,
49	};
50	
51	const INSURANCE_VALUE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
64	
65	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOWUP_DISCOUNT_RATE = 0.15;
72	const PROCESSING_FEE = 5;
73	const ROUNDING_PRECISION = 6;
74	
75	const roundTo = (value: number, direction: "up" | "down"): number => {
76	  const fixed = Number(value.toFixed(ROUNDING_PRECISION));
77	  return direction === "up" ? Math.ceil(fixed) : Math.floor(fixed);
78	};
79	
80	const componentBasePremium = (count: number): number => {
81	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
82	  return count * COMPONENT_PREMIUM;
83	};
84	
85	const COMPONENT_TYPES = ["rune", "moonstone"];
86	
87	const KNOWN_TYPES = [...Object.keys(MAIN_ITEM_PREMIUM), ...COMPONENT_TYPES];
88	
89	const validateKnownTypes = (items: Item[]): void => {
90	  for (const item of items) {
91	    if (!KNOWN_TYPES.includes(item.type)) {
92	      throw new Error(`unknown item type: ${item.type}`);
93	    }
94	  }
95	};
96	
97	const tally = (types: string[]): Map<string, number> => {
98	  const counts = new Map<string, number>();
99	  for (const type of types) {
100	    counts.set(type, (counts.get(type) ?? 0) + 1);
101	  }
102	  return counts;
103	};
104	
105	const countComponentsByType = (items: Item[]): Map<string, number> =>
106	  tally(
107	    items.map((item) => item.type).filter((type) => COMPONENT_TYPES.includes(type)),
108	  );
109	
110	const componentsBasePremium = (items: Item[]): number => {
111	  const counts = [...countComponentsByType(items).values()];
112	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
113	};
114	
115	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
116	
117	const mainItemsBasePremium = (items: Item[]): number =>
118	  items.reduce((total, item) => total + itemBasePremium(item), 0);
119	
120	const policyBasePremium = (items: Item[]): number =>
121	  mainItemsBasePremium(items) + componentsBasePremium(items);
122	
123	const isHighEnchantment = (item: Item): boolean =>
124	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
125	
126	const surchargeWhen = (applies: boolean, rate: number, base: number): number =>
127	  applies ? rate * base : 0;
128	
129	const itemSurcharge = (item: Item): number => {
130	  const base = itemBasePremium(item);
131	  return (
132	    surchargeWhen(item.cursed === true, CURSE_SURCHARGE_RATE, base) +
133	    surchargeWhen(isHighEnchantment(item), HIGH_ENCHANTMENT_SURCHARGE_RATE, base)
134	  );
135	};
136	
137	const itemSurcharges = (items: Item[]): number =>
138	  items.reduce((total, item) => total + itemSurcharge(item), 0);
139	
140	const isLoyalCustomer = (customer: Customer): boolean =>
141	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
142	
143	const loyaltyDiscount = (base: number, customer: Customer): number =>
144	  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
145	
146	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
147	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
148	
149	const quotePremium = (
150	  items: Item[],
151	  customer: Customer,
152	  isFollowUp: boolean,
153	): number => {
154	  validateKnownTypes(items);
155	  const base = policyBasePremium(items);
156	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
157	  const total =
158	    base +
159	    itemSurcharges(items) +
160	    firstInsurance -
161	    loyaltyDiscount(base, customer) -
162	    followUpDiscount(base, isFollowUp) +
163	    PROCESSING_FEE;
164	  return roundTo(total, "up");
165	};
166	
167	const insuranceSum = (items: Item[]): number =>
168	  items.reduce((total, item) => total + (INSURANCE_VALUE[item.type] ?? 0), 0);
169	
170	const reimbursement = (amount: number, insuredItem: Item): number =>
171	  (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
172	    ? HIGH_ENCHANTMENT_PAYOUT_RATE * amount
173	    : amount;
174	
175	const damagePayout = (damage: Damage, insuredItem: Item): number =>
176	  reimbursement(damage.amount, insuredItem) - DEDUCTIBLE;
177	
178	const payoutForDamage = (damage: Damage, items: Item[]): number => {
179	  const insuredItem = items.find((item) => item.type === damage.itemType) as Item;
180	  return damagePayout(damage, insuredItem);
181	};
182	
183	const incidentPayout = (incident: Incident, items: Item[]): number =>
184	  incident.damages.reduce(
185	    (total, damage) => total + payoutForDamage(damage, items),
186	    0,
187	  );
188	
189	const initialCap = (items: Item[]): number =>
190	  CAP_MULTIPLIER * insuranceSum(items);
191	
192	const validateDamageAmounts = (incident: Incident): void => {
193	  for (const damage of incident.damages) {
194	    if (damage.amount < 0) {
195	      throw new Error("damage amount must not be negative");
196	    }
197	  }
198	};
199	
200	const validateDamageCounts = (incident: Incident, items: Item[]): void => {
201	  const insured = tally(items.map((item) => item.type));
202	  const damaged = tally(incident.damages.map((damage) => damage.itemType));
203	  for (const [type, count] of damaged) {
204	    if (count > (insured.get(type) ?? 0)) {
205	      throw new Error(`claim references more ${type} than insured`);
206	    }
207	  }
208	};
209	
210	const claimResult = (
211	  step: ClaimStep,
212	  scenario: Scenario,
213	  remainingCapByPolicy: Map<number, number>,
214	): { payout: number; remainingCap: number } => {
215	  const policy = scenario.steps[step.policy] as QuoteStep;
216	  validateDamageAmounts(step.incident);
217	  validateDamageCounts(step.incident, policy.items);
218	  const remainingCap =
219	    remainingCapByPolicy.get(step.policy) ?? initialCap(policy.items);
220	  const rawPayout = incidentPayout(step.incident, policy.items);
221	  const payout = roundTo(Math.min(rawPayout, remainingCap), "down");
222	  const newRemainingCap = remainingCap - payout;
223	  remainingCapByPolicy.set(step.policy, newRemainingCap);
224	  return { payout, remainingCap: newRemainingCap };
225	};
226	
227	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
228	  let quoteCount = 0;
229	  const remainingCapByPolicy = new Map<number, number>();
230	  const results = scenario.steps.map((step) => {
231	    if (step.op === "claim") {
232	      return claimResult(step, scenario, remainingCapByPolicy);
233	    }
234	    const isFollowUp = quoteCount > 0;
235	    quoteCount += 1;
236	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
237	  });
238	  return { results };
239	};
